import rhumbBearing from '@turf/rhumb-bearing';

export const getArrowsAngles = (coordinates: number[][]) => {
  if (coordinates.length < 2) {
    return {
      startMarkerAngle: 0,
      endMarkerAngle: 0,
    };
  }

  const startArrowCoords = [coordinates[0], coordinates[1]];

  const endArrowCoords = [
    coordinates[coordinates.length - 2],
    coordinates[coordinates.length - 1],
  ];

  return {
    startMarkerAngle: rhumbBearing(startArrowCoords[1], startArrowCoords[0]),
    endMarkerAngle: rhumbBearing(endArrowCoords[0], endArrowCoords[1]),
  };
};
